mapper.select:
SELECT 
FROM mall_order ord
LEFT JOIN mall_payment pay ON ord.order_no = pay.order_no AND pay.payment_status = 'SUCCESS'
WHERE ord.status = #{status}
ORDER BY ${sortColumn} ${sortDir}

mapper.insert:
INSERT INTO mall_order (
    order_no, user_id, total_amount, pay_amount, freight, status,
    receiver_name, receiver_phone, receiver_address, remark
) VALUES (
    #{orderNo}, #{userId}, #{totalAmount}, #{payAmount}, #{freight}, #{status},
    #{receiverName}, #{receiverPhone}, #{receiverAddress}, #{remark}
)

mapper.update:
UPDATE mall_order
SET status = #{newStatus},
    updated_at = CURRENT_TIMESTAMP
WHERE order_no = #{orderNo}
  AND status = #{expectedStatus}

mapper.select:
SELECT 
FROM mall_order ord
WHERE ord.status IN ('COMPLETED', 'CANCELLED')
  AND ord.created_at < #{threshold}
ORDER BY ord.id ASC
LIMIT #{limit}

